#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>
#include <string.h>

// Simple hash table for 64‑bit integers (open addressing)
typedef struct {
    long long key;
    bool used;
} Cell;

static Cell *table;
static size_t cap;
static size_t mask;

static void init_table(size_t n){
    // size power of two >= 2*n
    cap = 1;
    while(cap < n*2) cap <<= 1;
    mask = cap-1;
    table = (Cell*)calloc(cap, sizeof(Cell));
}

static void free_table(){
    free(table);
    table = NULL;
    cap = mask = 0;
}

static bool insert_find(long long x, bool find){
    size_t h = (size_t)(x ^ (x>>32)) & mask;
    while(table[h].used){
        if(table[h].key == x){
            return true; // found
        }
        h = (h+1) & mask;
    }
    if(!find){
        table[h].used = true;
        table[h].key = x;
    }
    return false; // not found
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; long long B; scanf("%d %lld", &N, &B);
        init_table(N);
        bool ok = false;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(!ok){
                if(B==0){
                    if(insert_find(x, true)) ok = true;
                }else{
                    if(insert_find(x+B, true) || insert_find(x-B, true)) ok = true;
                }
            }
            insert_find(x, false);
        }
        free_table();
        printf("%d\n", ok?1:0);
    }
    return 0;
}

