        int N; long long B; cin>>N>>B;
        unordered_set<long long> seen;
        seen.reserve(N*2);
        bool ok=false;
        for(int i=0;i<N;i++){
            long long x; cin>>x;
            if(!ok){
                if(B==0){
                    if(seen.count(x)) ok=true;
                }else{
                    if(seen.count(x+B) || seen.count(x-B)) ok=true;
                }
            }
            seen.insert(x);
        }
        cout<<(ok?1:0) << '\n';
    }
    return 0;
}

