import sys
def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); B = int(next(it))
        seen = set()
        ok = False
        for _ in range(N):
            x = int(next(it))
            if not ok:
                if B == 0:
                    if x in seen:
                        ok = True
                else:
                    if (x + B) in seen or (x - B) in seen:
                        ok = True
            seen.add(x)
        out.append('1' if ok else '0')
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    solve()

